Telemetry implementation:
```typescript
// src/telemetry/emit.ts
import { appendFile } from 'fs/promises';
import { resolveTelemetryPath, isTelemetryEnabled } from './config';

export async function emit(eventType: string, data: Record<string, unknown>): Promise<void> {
  if (!isTelemetryEnabled()) return;
  const event = {
    timestamp: new Date().toISOString(),
    eventType,
    ...data,
  };
  await appendFile(resolveTelemetryPath(), JSON.stringify(event) + '\n', { mode: 0o600 });
}
```

